+import { Component } from '@angular/core';
+import { HttpClient, HttpContext } from '@angular/common/http';
+import { BYPASS_LOADING } from '../loadingInteceptor/loading.interceptor';
+
+@Component({
+  selector: 'app-chatbot',
+  templateUrl: './chatbot.component.html',
+  styleUrls: ['./chatbot.component.scss']
+})
+export class ChatbotComponent {
+  isOpen = false;
+  messages: { from: 'user' | 'bot'; text: string }[] = [];
+  inputMessage = '';
+  isLoading = false;
+
+  constructor(private http: HttpClient) {}
+
+  toggleChat() {
+    this.isOpen = !this.isOpen;
+  }
+
+  sendMessage() {
+    const msg = this.inputMessage.trim();
+    if (!msg || this.isLoading) return;
+
+    this.messages.push({
+      from: 'user',
+      text: msg
+    });
+
+    this.isLoading = true;
+
+    const token = "abc12213421";
+
+    this.http.post<{ response: string }>(
+      'http://localhost:2000/bs-user/api/chat',
+      { message: msg },
+      {
+        headers: {
+          Authorization: `Bearer ${token}`,
+          'Content-Type': 'application/json',
+          'Accept': 'application/json'
+        },
+        context: new HttpContext().set(BYPASS_LOADING, true) // Bỏ qua loading interceptor
+      }
+    ).subscribe({
+      next: (res) => {
+        console.log('API response:', res);
+        this.messages.push({ from: 'bot', text: res.response });
+        this.isLoading = false;
+      },
+      error: (err) => {
+        console.error('AI Error:', err);
+        this.messages.push({ from: 'bot', text: 'Xin lỗi, có lỗi khi xử lý yêu cầu: ' + err.message });
+        this.isLoading = false;
+      }
+    });
+
+    this.inputMessage = '';
+  }
+}
